const defaults = {
  title: '我要送快递可是你非要我做董事长',
  book_id: 'kuaidi_dongshizhang',
  chapter_count: 20,
  target_words_per_chapter: 2500,
  optional_genre: '都市轻喜剧爽文',
  style_preference: '轻松、反套路、节奏快、带职场讽刺和底层智慧的爽感',
  forbidden: ['不要把主角写成天生霸总', '不要让商业问题靠一句话无脑解决'],
  openai_model: ''
};
const raw = $json || {};
const incoming = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const title = incoming.title || incoming.bookTitle || defaults.title;
const safeBookId = String(incoming.book_id || incoming.bookId || defaults.book_id || title)
  .trim()
  .replace(/[\\/:*?"<>|\s]+/g, '_')
  .replace(/^_+|_+$/g, '')
  .slice(0, 80) || 'book';
return [{ json: {
  ...defaults,
  ...incoming,
  title,
  bookTitle: title,
  book_id: safeBookId,
  chapter_count: Number(incoming.chapter_count || incoming.chapterCount || defaults.chapter_count),
  target_words_per_chapter: Number(incoming.target_words_per_chapter || incoming.chapterTargetWords || defaults.target_words_per_chapter),
  openai_model: incoming.openai_model || incoming.model || defaults.openai_model
} }];

const init = $('Init Params').item.json;
const promptTemplate = $('Load Seed Prompt').item.json.content;
const schema = $json.schema || $json;
const payload = {
  title: init.title,
  chapter_count: init.chapter_count,
  optional_genre: init.optional_genre,
  style_preference: init.style_preference,
  forbidden: init.forbidden
};
const prompt = `${promptTemplate}\n\n请根据以下输入生成故事种子。\n输入：\n${JSON.stringify(payload, null, 2)}\n\n必须严格符合以下 JSON Schema，不要输出 Markdown，不要输出解释：\n${JSON.stringify(schema, null, 2)}`;
return [{ json: { ...init, prompt } }];

const init = $('Build GPT Seed Request').item.json;
let response = $json;
if (typeof response === 'string') {
  try { response = JSON.parse(response); } catch (err) { response = { data: response }; }
}
if (typeof response.data === 'string') {
  try { response = JSON.parse(response.data); } catch (err) {}
}
if (response.body && typeof response.body === 'string') {
  try { response = JSON.parse(response.body); } catch (err) {}
}
const raw = response.choices?.[0]?.message?.content
  || response.content?.[0]?.text
  || response.output_text
  || response.text
  || response.data?.choices?.[0]?.message?.content
  || '';
let txt = String(raw).trim();
if (txt.startsWith('```')) {
  txt = txt.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
}
const s = txt.indexOf('{');
const e = txt.lastIndexOf('}');
if (s !== -1 && e !== -1 && e > s) txt = txt.slice(s, e + 1);
let storySeed;
try {
  storySeed = JSON.parse(txt);
} catch (err) {
  throw new Error('Story seed JSON parse failed: ' + raw);
}
return [{ json: { ...init, story_seed: storySeed, story_seed_raw: raw } }];

const seedNode = $('Parse Story Seed').item.json;
const promptTemplate = $json.content;
const storySeed = seedNode.story_seed;
const prompt = `${promptTemplate}

请基于以下 story_seed 生成小说圣经。
story_seed：
${JSON.stringify(storySeed, null, 2)}

要求：
1. 只输出 Markdown 正文。
2. 标题层级清晰。
3. 内容要能直接保存为 bible/story_bible.md。
4. 不要输出代码块包裹。
5. 控制在 3500-6000 个中文字符，优先保留角色、主线、势力、规则、伏笔和文风约束，不要展开正文。`;
return [{ json: { ...seedNode, prompt } }];

const seedNode = $('Build GPT Story Bible Request').item.json;
let response = $json;
if (typeof response === 'string') {
  try { response = JSON.parse(response); } catch (err) { response = { data: response }; }
}
if (typeof response.data === 'string') {
  try { response = JSON.parse(response.data); } catch (err) {}
}
if (response.body && typeof response.body === 'string') {
  try { response = JSON.parse(response.body); } catch (err) {}
}
let markdown = response.choices?.[0]?.message?.content
  || response.content?.[0]?.text
  || response.output_text
  || response.text
  || response.data?.choices?.[0]?.message?.content
  || '';
markdown = String(markdown).trim();
if (markdown.startsWith('```')) {
  markdown = markdown.replace(/^```(?:markdown|md)?\s*/i, '').replace(/```$/i, '').trim();
}
if (!markdown) throw new Error('Story bible markdown is empty');
return [{ json: { ...seedNode, story_bible_markdown: markdown } }];

const seedNode = $('Parse Story Seed').item.json;
const storyBible = $('Parse Story Bible').item.json.story_bible_markdown;
const promptTemplate = $('Load Outline Prompt').item.json.content;
const schema = $json.schema || $json;
const payload = {
  story_bible: storyBible,
  chapter_count: seedNode.chapter_count || 20,
  target_words_per_chapter: seedNode.target_words_per_chapter || 2500
};
const prompt = `${promptTemplate}

请基于以下小说圣经生成 20 章大纲。
输入：
${JSON.stringify(payload, null, 2)}

必须严格符合以下 JSON Schema，只输出 JSON，不要输出 Markdown 或解释：
${JSON.stringify(schema, null, 2)}`;
return [{ json: { ...seedNode, story_bible_markdown: storyBible, prompt } }];

const source = $('Build GPT Outline Request').item.json;
let response = $json;
if (typeof response === 'string') {
  try { response = JSON.parse(response); } catch (err) { response = { data: response }; }
}
if (typeof response.data === 'string') {
  try { response = JSON.parse(response.data); } catch (err) {}
}
if (response.body && typeof response.body === 'string') {
  try { response = JSON.parse(response.body); } catch (err) {}
}
const raw = response.choices?.[0]?.message?.content
  || response.content?.[0]?.text
  || response.output_text
  || response.text
  || response.data?.choices?.[0]?.message?.content
  || '';
let txt = String(raw).trim();
if (txt.startsWith('```')) {
  txt = txt.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
}
const s = txt.indexOf('{');
const e = txt.lastIndexOf('}');
if (s !== -1 && e !== -1 && e > s) txt = txt.slice(s, e + 1);
let outline;
try {
  outline = JSON.parse(txt);
} catch (err) {
