if (!Array.isArray(outline.chapters) || outline.chapters.length !== 20) {
  throw new Error('Outline must contain exactly 20 chapters, got ' + (outline.chapters || []).length);
}
return [{ json: { ...source, outline_20: outline, outline_20_raw: raw } }];

const seed = $('Parse Story Seed').item.json;
const chapterTask = $('Parse Chapter 1 Task').item.json.chapter_task;
const sceneCards = $('Parse Chapter 1 Scene Cards').item.json.scene_cards;
return [{ json: {
  ok: true,
  book_id: seed.book_id,
  title: seed.title,
  saved_paths: [
    'bible/story_seed.json',
    'bible/story_bible.md',
    'outline/chapters_20.json',
    'chapter_tasks/ch001.task.json',
    'scenes/ch001.scenes.json'
  ],
  chapter_1: {
    title: chapterTask.chapter_title,
    scene_count: sceneCards.scenes.length
  },
  next_step: '生成第 1 章正文场景并合并为 chapters/ch001.md'
} }];

const source = $('Parse Outline 20').item.json;
const promptTemplate = $('Load Chapter Task Prompt').item.json.content;
const schema = $json.schema || $json;
const chapterIndex = Number(source.start_chapter || source.chapter_index || 1);
const outline = source.outline_20;
const chapterPlan = outline.chapters.find(ch => Number(ch.chapter_index) === chapterIndex);
if (!chapterPlan) throw new Error('Chapter plan not found for chapter ' + chapterIndex);
const storySeed = source.story_seed || {};
const stateMemory = {
  characters: [],
  locations: [],
  organizations: [],
  must_remember: [
    '主角设定：' + JSON.stringify(storySeed.protagonist_seed || {}, null, 2),
    '主线冲突：' + (storySeed.main_conflict || ''),
    '阶段结局：' + (storySeed.stage_ending || ''),
    ...((storySeed.forbidden || []).map(item => '禁忌：' + item))
  ].filter(Boolean)
};
const payload = {
  story_bible: source.story_bible_markdown,
  chapter_plan: chapterPlan,
  recent_summaries: [],
  state_memory: stateMemory,
  active_foreshadowing: []
};
const prompt = `${promptTemplate}

请基于以下输入生成第 ${chapterIndex} 章任务单。
输入：
${JSON.stringify(payload, null, 2)}

必须严格符合以下 JSON Schema，只输出 JSON，不要输出 Markdown 或解释：
${JSON.stringify(schema, null, 2)}`;
return [{ json: { ...source, chapter_index: chapterIndex, chapter_plan: chapterPlan, state_memory: stateMemory, prompt } }];

function extractContent(response) {
  if (typeof response === 'string') {
    try { response = JSON.parse(response); } catch (err) { response = { data: response }; }
  }
  if (typeof response.data === 'string') {
    try { response = JSON.parse(response.data); } catch (err) {}
  }
  if (response.body && typeof response.body === 'string') {
    try { response = JSON.parse(response.body); } catch (err) {}
  }
  return response.choices?.[0]?.message?.content
    || response.content?.[0]?.text
    || response.output_text
    || response.text
    || response.data?.choices?.[0]?.message?.content
    || '';
}
function parseJsonFromText(raw, label) {
  let txt = String(raw).trim();
  if (txt.startsWith('```')) {
    txt = txt.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  }
  const s = txt.indexOf('{');
  const e = txt.lastIndexOf('}');
  if (s !== -1 && e !== -1 && e > s) txt = txt.slice(s, e + 1);
  try {
    return JSON.parse(txt);
  } catch (err) {
    throw new Error(label + ' JSON parse failed: ' + raw);
  }
}
const source = $('Build GPT Chapter 1 Task Request').item.json;
const raw = extractContent($json);
const task = parseJsonFromText(raw, 'Chapter task');
const required = ['chapter_index','chapter_title','opening_state','ending_state','protagonist_goal','obstacle','required_information','avoid_conflicts','emotion_curve','cliffhanger','next_chapter_bridge'];
for (const key of required) {
  if (!(key in task)) throw new Error('Chapter task missing field: ' + key);
}
if (Number(task.chapter_index) !== Number(source.chapter_index)) {
  task.chapter_index = Number(source.chapter_index);
}
return [{ json: { ...source, chapter_task: task, chapter_task_raw: raw } }];

const source = $('Parse Chapter 1 Task').item.json;
const promptTemplate = $('Load Scene Cards Prompt').item.json.content;
const schema = $json.schema || $json;
const payload = {
  chapter_task: source.chapter_task,
  story_bible: source.story_bible_markdown,
  state_memory: source.state_memory || {}
};
const prompt = `${promptTemplate}

请基于以下输入拆分第 ${source.chapter_index} 章场景卡。
输入：
${JSON.stringify(payload, null, 2)}

必须严格符合以下 JSON Schema，只输出 JSON，不要输出 Markdown 或解释：
${JSON.stringify(schema, null, 2)}`;
return [{ json: { ...source, prompt } }];

