const source = $('Build GPT Chapter 1 Scene Cards Request').item.json;
const raw = extractContent($json);
const sceneCards = parseJsonFromText(raw, 'Scene cards');
if (Number(sceneCards.chapter_index) !== Number(source.chapter_index)) {
  sceneCards.chapter_index = Number(source.chapter_index);
}
if (!Array.isArray(sceneCards.scenes) || sceneCards.scenes.length < 3 || sceneCards.scenes.length > 5) {
  throw new Error('Scene cards must contain 3-5 scenes, got ' + (sceneCards.scenes || []).length);
}
for (let i = 0; i < sceneCards.scenes.length; i++) {
  sceneCards.scenes[i].scene_index = Number(sceneCards.scenes[i].scene_index || i + 1);
}
return [{ json: { ...source, scene_cards: sceneCards, scene_cards_raw: raw } }];
